// Parse scraped HTML and extract structured listing data
// In production, adapt selectors to your target site (Domain, REA, Zillow, Rightmove, etc.)

const config = $('Configure Scrape Targets').first().json;
const htmlText = $input.first().json.data || '';

// Simple regex-based extraction (replace with Cheerio/puppeteer for production)
// This simulates extracting listings from JSON-LD or data attributes
const listings = [];

// Try to find JSON-LD structured data (many property sites use this)
const jsonLdMatches = htmlText.match(/<script type="application\/ld\+json">[\s\S]*?<\/script>/gi) || [];
for (const match of jsonLdMatches) {
  try {
    const jsonContent = match.replace(/<script[^>]*>/i, '').replace(/<\/script>/i, '').trim();
    const data = JSON.parse(jsonContent);
    if (data['@type'] === 'RealEstateListing' || data['@type'] === 'Residence') {
      listings.push({
        listingId: `LST-${Math.random().toString(36).substr(2, 8).toUpperCase()}`,
        address: data.name || data.address?.streetAddress || 'Unknown',
        suburb: data.address?.addressLocality || config.suburb,
        state: data.address?.addressRegion || 'NSW',
        postcode: data.address?.postalCode || '2000',
        price: parseFloat((data.offers?.price || '0').toString().replace(/[^0-9.]/g, '')) || null,
        priceText: data.offers?.price || 'Price on application',
        bedrooms: parseInt(data.numberOfRooms) || null,
        bathrooms: parseInt(data.numberOfBathroomsTotal) || null,
        carSpaces: parseInt(data.numberOfParkingSpaces) || null,
        propertyType: data['@type'] || 'House',
        landSize: data.floorSize?.value || null,
        description: (data.description || '').substring(0, 500),
        listingUrl: data.url || config.searchUrl,
        imageUrl: data.image?.[0] || null,
        agent: data.agent?.name || 'Unknown Agent',
        listedAt: data.datePosted || new Date().toISOString()
      });
    }
  } catch (e) { /* skip malformed JSON-LD */ }
}

// Fallback: generate synthetic listings for demonstration if no structured data found
if (listings.length === 0) {
  const suburbs = [config.suburb, 'Parramatta', 'Blacktown', 'Liverpool', 'Penrith'];
  const types = ['House', 'Unit', 'Townhouse', 'Villa'];
  const count = Math.min(config.maxListings || 10, 12);
  for (let i = 0; i < count; i++) {
    const suburb = suburbs[i % suburbs.length];
    const type = types[i % types.length];
    const beds = Math.floor(Math.random() * 3) + 2;
    const basePrice = type === 'Unit' ? 550000 : type === 'House' ? 850000 : 700000;
    const price = basePrice + Math.floor(Math.random() * 300000);
    listings.push({
      listingId: `LST-${Math.random().toString(36).substr(2, 8).toUpperCase()}`,
      address: `${Math.floor(Math.random() * 99) + 1} Sample Street`,
      suburb,
      state: 'NSW',
      postcode: `2${150 + i}`,
      price,
      priceText: `$${price.toLocaleString()}`,
      bedrooms: beds,
      bathrooms: beds - 1 || 1,
      carSpaces: type === 'Unit' ? 1 : 2,
      propertyType: type,
      landSize: type === 'House' ? Math.floor(Math.random() * 400) + 300 : null,
      description: `${beds} bedroom ${type.toLowerCase()} in ${suburb}. Close to transport, schools and shops.`,
      listingUrl: `${config.searchUrl}/${i + 1}`,
      imageUrl: null,
      agent: 'Demo Real Estate',
      listedAt: new Date().toISOString()
    });
  }
}

// Attach job metadata
const jobConfig = config;
return listings.slice(0, config.maxListings || 15).map(l => ({
  json: { listing: l, jobConfig }
}));

const listing = $('Parse Listing Data').item.json.listing;
const jobConfig = $('Parse Listing Data').item.json.jobConfig;

const marketRaw = $('Fetch Suburb Market Data').item.json;
const demoRaw = $('Fetch Area Demographics').item.json;
const rentalRaw = $('Fetch Rental Yield Data').item.json;

// Parse market data (adapt to actual API response shape)
let marketData = {
  suburbMedianPrice: null,
  medianPriceGrowth1yr: null,
  medianPriceGrowth5yr: null,
  suburbMedianRent: null,
  grossRentalYield: null,
  daysOnMarket: null,
  clearanceRate: null
};
try {
  if (marketRaw && !marketRaw.error) {
    const d = marketRaw.data || marketRaw;
    marketData = {
      suburbMedianPrice: d.medianSalePrice || d.median_price || null,
      medianPriceGrowth1yr: d.priceGrowth1yr || d.growth_1yr || null,
      medianPriceGrowth5yr: d.priceGrowth5yr || d.growth_5yr || null,
      suburbMedianRent: d.medianWeeklyRent || d.median_rent || null,
      grossRentalYield: d.grossRentalYield || d.yield || null,
      daysOnMarket: d.medianDaysOnMarket || d.days_on_market || null,
      clearanceRate: d.auctionClearanceRate || null
    };
  } else {
    // Synthetic fallback for demo
    const syntheticYield = (2.8 + Math.random() * 3).toFixed(2);
    marketData = {
      suburbMedianPrice: listing.price ? Math.round(listing.price * (0.9 + Math.random() * 0.2)) : 750000,
      medianPriceGrowth1yr: parseFloat((Math.random() * 10 - 2).toFixed(1)),
      medianPriceGrowth5yr: parseFloat((Math.random() * 40 + 5).toFixed(1)),
      suburbMedianRent: Math.round((listing.price * parseFloat(syntheticYield) / 100) / 52),
      grossRentalYield: parseFloat(syntheticYield),
      daysOnMarket: Math.floor(Math.random() * 45) + 15,
      clearanceRate: parseFloat((55 + Math.random() * 30).toFixed(1))
    };
  }
} catch (e) { console.log('Market parse error:', e.message); }

// Parse demographics
let demographics = {
  populationGrowth: null,
  medianHouseholdIncome: null,
  unemploymentRate: null
};
try {
  if (demoRaw && !demoRaw.error) {
    const d = demoRaw.data || demoRaw;
    demographics = {
      populationGrowth: d.populationGrowth || d.pop_growth || null,
      medianHouseholdIncome: d.medianIncome || d.median_income || null,
      unemploymentRate: d.unemploymentRate || d.unemployment || null
    };
  } else {
    demographics = {
      populationGrowth: parseFloat((0.5 + Math.random() * 2.5).toFixed(1)),
      medianHouseholdIncome: Math.round(70000 + Math.random() * 60000),
      unemploymentRate: parseFloat((3 + Math.random() * 5).toFixed(1))
    };
  }
} catch (e) { console.log('Demo parse error:', e.message); }

// Parse rental / vacancy
let rentalMetrics = {
  vacancyRate: null,
  rentalDemandScore: null,
  avgWeeklyRent: null
};
try {
  if (rentalRaw && !rentalRaw.error) {
    const d = rentalRaw.data || rentalRaw;
    rentalMetrics = {
      vacancyRate: d.vacancyRate || d.vacancy_rate || null,
      rentalDemandScore: d.demandScore || null,
      avgWeeklyRent: d.avgWeeklyRent || d.avg_rent || null
    };
  } else {
    const vacancy = parseFloat((0.5 + Math.random() * 4).toFixed(2));
    const weeklyRent = Math.round(350 + Math.random() * 500);
    rentalMetrics = {
      vacancyRate: vacancy,
      rentalDemandScore: Math.round(Math.max(0, Math.min(100, 100 - vacancy * 15))),
      avgWeeklyRent: weeklyRent
    };
  }
} catch (e) { console.log('Rental parse error:', e.message); }

// Compute estimated financials
const purchasePrice = listing.price || marketData.suburbMedianPrice || 750000;
const weeklyRent = rentalMetrics.avgWeeklyRent || marketData.suburbMedianRent || 500;
const annualRent = weeklyRent * 52;
const grossYield = marketData.grossRentalYield || parseFloat(((annualRent / purchasePrice) * 100).toFixed(2));
const expenses = annualRent * 0.28; // strata, PM, rates, insurance ~28%
const netAnnualIncome = annualRent - expenses;
const netYield = parseFloat(((netAnnualIncome / purchasePrice) * 100).toFixed(2));
const interestRate = 6.5; // current avg mortgage rate
const loanAmount = purchasePrice * 0.8;
const annualInterest = loanAmount * (interestRate / 100);
const weeklyInterest = annualInterest / 52;
const weeklyNetCashFlow = weeklyRent - weeklyInterest - (expenses / 52);

return {
  json: {
    listing,
    jobConfig,
    marketData,
    demographics,
    rentalMetrics,
    financials: {
      purchasePrice,
      weeklyRent,
      annualRent,
      grossYield,
      netYield,
      estimatedWeeklyCashFlow: parseFloat(weeklyNetCashFlow.toFixed(2)),
      assumedLVR: 80,
      assumedInterestRate: interestRate,
      enrichedAt: new Date().toISOString()
    }
  }
};

const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let aiScore;
try {
  aiScore = JSON.parse(cleanText);
} catch (error) {
  // Attempt extraction of JSON block
  const match = cleanText.match(/\{[\s\S]*\}/);
  if (match) {
    aiScore = JSON.parse(match[0]);
  } else {
    throw new Error(`Failed to parse Claude response: ${error.message}. Raw: ${cleanText.substring(0, 300)}`);
  }
}

const enriched = $('Combine All Property Data').item.json;

return {
  json: {
    listingId: enriched.listing.listingId,
    address: `${enriched.listing.address}, ${enriched.listing.suburb} ${enriched.listing.state}`,
    suburb: enriched.listing.suburb,
    propertyType: enriched.listing.propertyType,
    askingPrice: enriched.listing.price,
    priceText: enriched.listing.priceText,
    bedrooms: enriched.listing.bedrooms,
    bathrooms: enriched.listing.bathrooms,
    listingUrl: enriched.listing.listingUrl,
    financials: enriched.financials,
    marketData: enriched.marketData,
    demographics: enriched.demographics,
    rentalMetrics: enriched.rentalMetrics,
    aiScore,
    jobConfig: enriched.jobConfig,
    scoredAt: new Date().toISOString()
  }
};

// Build a summary report from all top picks
const items = $input.all();
const jobConfig = items[0]?.json.jobConfig || {};

const topPicks = items.map(item => {
  const d = item.json;
  const score = d.aiScore;
  return {
    rank: 0, // filled below
    listingId: d.listingId,
    address: d.address,
    propertyType: d.propertyType,
    bedrooms: d.bedrooms,
    askingPrice: d.priceText,
    investmentScore: score.investmentScore,
    rating: score.rating,
    recommendation: score.recommendation,
    projectedGrossYield: score.projectedGrossYield,
    projectedNetYield: score.projectedNetYield,
    estimatedWeeklyCashFlow: d.financials.estimatedWeeklyCashFlow,
    capitalGrowthOutlook: score.capitalGrowthOutlook,
    priceVsFairValue: score.priceVsFairValue,
    suggestedOfferPrice: score.suggestedOfferPrice,
    summary: score.summary,
    strengths: score.strengths,
    weaknesses: score.weaknesses,
    riskFlags: score.riskFlags,
    holdPeriodRecommendation: score.holdPeriodRecommendation,
    listingUrl: d.listingUrl,
    scoredAt: d.scoredAt
  };
}).sort((a, b) => b.investmentScore - a.investmentScore)
  .map((p, i) => ({ ...p, rank: i + 1 }));

const slackBlocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `🏠 Daily Property Investment Report — ${new Date().toLocaleDateString('en-AU')}` }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*${topPicks.length} top pick(s)* above score threshold of *${jobConfig.scoreThreshold || 65}/100*`
    }
  },
  { type: 'divider' }
];

for (const p of topPicks.slice(0, 5)) {
  slackBlocks.push({
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*#${p.rank} — ${p.address}*` },
      { type: 'mrkdwn', text: `*Score:* ${p.investmentScore}/100 (${p.rating})` },
      { type: 'mrkdwn', text: `*Price:* ${p.askingPrice}` },
      { type: 'mrkdwn', text: `*Yield:* ${p.projectedGrossYield}% gross / ${p.projectedNetYield}% net` },
      { type: 'mrkdwn', text: `*Cash Flow:* $${p.estimatedWeeklyCashFlow}/wk` },
      { type: 'mrkdwn', text: `*Capital Growth:* ${p.capitalGrowthOutlook}` },
      { type: 'mrkdwn', text: `*Pricing:* ${p.priceVsFairValue} (offer: $${p.suggestedOfferPrice?.toLocaleString()})` },
      { type: 'mrkdwn', text: `*Recommendation:* ${p.recommendation}` }
    ]
  });
  slackBlocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `_${p.summary}_\n<${p.listingUrl}|View Listing>` }
  });
  slackBlocks.push({ type: 'divider' });
}

return [{
  json: {
    reportDate: new Date().toISOString(),
    jobId: jobConfig.jobId,
    suburb: jobConfig.suburb,
    totalAnalysed: items.length,
    topPicksCount: topPicks.length,
    scoreThreshold: jobConfig.scoreThreshold || 65,
    topPicks,
    slackBlocks,
    generatedAt: new Date().toISOString()
  }
}];

